What does this program print to `std::cout` when the input is `4`? (Ignore `std::cerr` output.)

```cpp
#include <iostream>

int double_it(int n)
{
    return n + n;
}

int add_five(int n)
{
    return n + 5;
}

int main()
{
    int x;
    std::cin >> x;
    int a = double_it(x);
    std::cerr << "after double: " << a << "\n";
    int b = add_five(a);
    std::cerr << "after add_five: " << b << "\n";
    std::cout << b << "\n";
    return 0;
}
```

For input `6`, what does the following print to `std::cout`? (Ignore cerr output.)

```cpp
#include <iostream>

int triple(int n)
{
    return n * 3;
}

int subtract_two(int n)
{
    return n - 2;
}

int main()
{
    int x;
    std::cin >> x;
    std::cerr << "x = " << x << "\n";
    int t = triple(x);
    std::cerr << "tripled = " << t << "\n";
    std::cout << subtract_two(t) << "\n";
    return 0;
}
```
